{"content": "import SpriteKit

/// 场景背景：天空渐变 + 飘移白云 + 太阳 + 草地
final class BackgroundNode: SKNode {

    init(frame: CGRect) {
        super.init()
        zPosition = -100

        drawSkyGradient(frame: frame)
        addSun(at: CGPoint(x: frame.maxX - 80, y: frame.maxY - 60))
        addClouds(frame: frame)
        addGrass(frame: frame)
    }

    required init?(coder aDecoder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }

    // MARK: - Sky gradient

    private func drawSkyGradient(frame: CGRect) {
        let renderer = UIGraphicsImageRenderer(size: frame.size)
        let image = renderer.image { ctx in
            let c = ctx.cgContext
            let colors = [
                UIColor(red: 0.45, green: 0.75, blue: 1.0, alpha: 1).cgColor,
                UIColor(red: 0.75, green: 0.90, blue: 1.0, alpha: 1).cgColor,
                UIColor(red: 0.92, green: 0.97, blue: 1.0, alpha: 1).cgColor,
            ] as CFArray
            let locations: [CGFloat] = [0, 0.55, 1.0]
            guard let gradient = CGGradient(colorsSpace: CGColorSpace(name: CGColorSpace.sRGB)!,
                                            colors: colors, locations: locations) else { return }
            c.drawLinearGradient(gradient,
                                 start: CGPoint(x: 0, y: frame.height),
                                 end: CGPoint(x: 0, y: 0),
                                 options: [])
        }
        let sky = SKSpriteNode(texture: SKTexture(image: image))
        sky.position = CGPoint(x: frame.midX, y: frame.midY)
        sky.zPosition = -3
        addChild(sky)
    }

    // MARK: - Sun

    private func addSun(at position: CGPoint) {
        let size = CGSize(width: 80, height: 80)
        let renderer = UIGraphicsImageRenderer(size: size)
        let image = renderer.image { ctx in
            let c = ctx.cgContext
            let center = CGPoint(x: 40, y: 40)

            // Ray bursts
            c.setStrokeColor(UIColor.yellow.withAlphaComponent(0.6).cgColor)
            c.setLineWidth(3)
            for i in 0..<12 {
                let angle = CGFloat(i) * .pi * 2 / 12
                let x1 = center.x + cos(angle) * 28
                let y1 = center.y + sin(angle) * 28
                let x2 = center.x + cos(angle) * 38
                let y2 = center.y + sin(angle) * 38
                c.move(to: CGPoint(x: x1, y: y1))
                c.addLine(to: CGPoint(x: x2, y: y2))
            }
            c.strokePath()

            // Sun body
            let gradientColors = [
                UIColor.yellow.cgColor,
                UIColor.orange.withAlphaComponent(0.7).cgColor,
            ] as CFArray
            let locations: [CGFloat] = [0, 1]
            guard let gradient = CGGradient(colorsSpace: CGColorSpace(name: CGColorSpace.sRGB)!,
                                            colors: gradientColors, locations: locations) else { return }
            c.addEllipse(in: CGRect(x: 10, y: 10, width: 60, height: 60))
            c.clip()
            c.drawLinearGradient(gradient, start: CGPoint(x: 40, y: 10), end: CGPoint(x: 40, y: 70), options: [])
        }
        let sun = SKSpriteNode(texture: SKTexture(image: image))
        sun.position = position
        sun.zPosition = -2
        addChild(sun)

        // Gentle bobbing
        let bob = SKAction.sequence([
            SKAction.moveBy(x: 0, y: 4, duration: 2.0),
            SKAction.moveBy(x: 0, y: -4, duration: 2.0),
        ])
        bob.timingMode = .easeInEaseOut
        sun.run(SKAction.repeatForever(bob))
    }

    // MARK: - Clouds

    private func addClouds(frame: CGRect) {
        let cloudPositions: [(CGPoint, CGFloat)] = [
            (CGPoint(x: frame.maxX * 0.15, y: frame.maxY * 0.78), 1.0),
            (CGPoint(x: frame.maxX * 0.45, y: frame.maxY * 0.85), 0.7),
            (CGPoint(x: frame.maxX * 0.75, y: frame.maxY * 0.73), 0.85),
        ]

        for (pos, scale) in cloudPositions {
            let cloud = makeCloud(scale: scale)
            cloud.position = pos
            cloud.zPosition = -1
            addChild(cloud)

            let duration: TimeInterval = 20 + TimeInterval(pos.x * 0.02)
            let drift = SKAction.sequence([
                SKAction.moveBy(x: frame.width + 200, y: 0, duration: duration),
                SKAction.moveTo(x: -200, duration: 0),
            ])
            cloud.run(SKAction.repeatForever(drift))
        }
    }

    private func makeCloud(scale: CGFloat) -> SKNode {
        let size = CGSize(width: 160 * scale, height: 60 * scale)
        let renderer = UIGraphicsImageRenderer(size: size)
        let image = renderer.image { ctx in
            let c = ctx.cgContext
            c.setFillColor(UIColor.white.withAlphaComponent(0.85).cgColor)

            // Uneven cloud blobs using overlapping ellipses
            let w = size.width
            let h = size.height
            c.fillEllipse(in: CGRect(x: w * 0.1, y: h * 0.25, width: w * 0.35, height: h * 0.7))
            c.fillEllipse(in: CGRect(x: w * 0.3, y: h * 0.05, width: w * 0.35, height: h * 0.9))
            c.fillEllipse(in: CGRect(x: w * 0.5, y: h * 0.2, width: w * 0.35, height: h * 0.75))
            c.fillEllipse(in: CGRect(x: w * 0.65, y: h * 0.3, width: w * 0.25, height: h * 0.6))
        }
        return SKSpriteNode(texture: SKTexture(image: image))
    }

    // MARK: - Grass

    private func addGrass(frame: CGRect) {
        let grassHeight: CGFloat = frame.height * 0.10
        let grassSize = CGSize(width: frame.width, height: grassHeight)
        let renderer = UIGraphicsImageRenderer(size: grassSize)
        let image = renderer.image { ctx in
            let c = ctx.cgContext
            let colors = [
                UIColor(red: 0.30, green: 0.78, blue: 0.35, alpha: 1).cgColor,
                UIColor(red: 0.18, green: 0.60, blue: 0.22, alpha: 1).cgColor,
            ] as CFArray
            guard let gradient = CGGradient(colorsSpace: CGColorSpace(name: CGColorSpace.sRGB)!,
                                            colors: colors, locations: [0, 1]) else { return }
            c.drawLinearGradient(gradient,
                                 start: CGPoint(x: 0, y: grassHeight),
                                 end: CGPoint(x: 0, y: 0),
                                 options: [])

            // Grass blade tufts along top edge
            c.setStrokeColor(UIColor(red: 0.25, green: 0.70, blue: 0.28, alpha: 1).cgColor)
            c.setLineWidth(2)
            let bladeCount = 60
            for i in 0...bladeCount {
                let x = CGFloat(i) * grassSize.width / CGFloat(bladeCount)
                let h = CGFloat.random(in: 4...10)
                c.move(to: CGPoint(x: x, y: grassHeight))
                c.addLine(to: CGPoint(x: x + 2, y: grassHeight - h))
            }
            c.strokePath()
        }
        let grass = SKSpriteNode(texture: SKTexture(image: image))
        grass.position = CGPoint(x: frame.midX, y: grassHeight / 2)
        grass.zPosition = -1
        grass.anchorPoint = CGPoint(x: 0.5, y: 0.5)
        addChild(grass)
    }
}
