{"content": "import SpriteKit

final class SlideNode: SKNode {
    let shape: SlideShape
    let layout: SlideLayout

    /// 角色滑行跟随的路径
    var slidePath: CGPath { layout.slidePath(for: shape) }

    private let bodySprite: SKSpriteNode

    // MARK: - Init

    init(shape: SlideShape, layout: SlideLayout) {
        self.shape = shape
        self.layout = layout
        bodySprite = SKSpriteNode()
        super.init()
        bodySprite.zPosition = 2
        addChild(bodySprite)
        renderTexture()
    }

    required init?(coder aDecoder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }

    // MARK: - Texture rendering

    private func renderTexture() {
        let canvas = slideCanvasRect()
        let size = canvas.size
        guard size.width > 0, size.height > 0 else { return }

        let renderer = UIGraphicsImageRenderer(size: size)
        let image = renderer.image { ctx in
            let c = ctx.cgContext
            c.translateBy(x: -canvas.origin.x, y: -canvas.origin.y)

            let (r, g, b) = shape.color
            let railColor = UIColor(red: r, green: g, blue: b, alpha: 1)
            let darkColor = UIColor(red: r * 0.3, green: g * 0.3, blue: b * 0.3, alpha: 1)
            let lightColor = UIColor(red: min(1, r * 1.2), green: min(1, g * 1.2), blue: min(1, b * 1.2), alpha: 1)

            // 1. Railing edge — thick white outline
            drawRail(path: slidePath, color: .white, width: 24, in: c)
            // 2. Dark outline
            drawRail(path: slidePath, color: darkColor, width: 20, in: c)
            // 3. Gradient rail surface
            drawGradientRail(path: slidePath, light: lightColor, dark: railColor, width: 14, in: c)
            // 4. White highlight on top
            drawHighlight(path: slidePath, width: 4, in: c)

            // 5. Railing posts (small vertical lines along the path)
            drawRailingPosts(path: slidePath, color: .white, in: c)

            // 6. Structural elements
            drawStructures(in: c)
        }

        bodySprite.texture = SKTexture(image: image)
        bodySprite.size = size
        bodySprite.position = CGPoint(x: canvas.midX, y: canvas.midY)
    }

    /// 画布矩形：滑梯全部可见范围
    private func slideCanvasRect() -> CGRect {
        let pad: CGFloat = 30
        return CGRect(
            x: layout.origin.x - pad,
            y: layout.groundY - pad,
            width: layout.slideEndX - layout.origin.x + 120,
            height: layout.topY - layout.groundY + pad * 2
        )
    }

    // MARK: - Rail drawing helpers

    private func drawRail(path: CGPath, color: UIColor, width: CGFloat, in c: CGContext) {
        c.setStrokeColor(color.cgColor)
        c.setLineWidth(width)
        c.setLineCap(.round)
        c.setLineJoin(.round)
        c.addPath(path)
        c.strokePath()
    }

    private func drawGradientRail(path: CGPath, light: UIColor, dark: UIColor, width: CGFloat, in c: CGContext) {
        c.saveGState()
        c.setLineWidth(width)
        c.setLineCap(.round)
        c.setLineJoin(.round)
        c.addPath(path)
        c.replacePathWithStrokedPath()
        c.clip()

        let colors = [light.cgColor, dark.cgColor] as CFArray
        let bbox = path.boundingBoxOfPath
        guard let gradient = CGGradient(colorsSpace: CGColorSpace(name: CGColorSpace.sRGB)!,
                                        colors: colors, locations: [0, 1]) else {
            c.restoreGState()
            return
        }
        c.drawLinearGradient(gradient,
                             start: CGPoint(x: bbox.midX, y: bbox.maxY),
                             end: CGPoint(x: bbox.midX, y: bbox.minY),
                             options: [])
        c.restoreGState()
    }

    private func drawHighlight(path: CGPath, width: CGFloat, in c: CGContext) {
        c.setStrokeColor(UIColor.white.withAlphaComponent(0.4).cgColor)
        c.setLineWidth(width)
        c.setLineCap(.round)
        c.setLineJoin(.round)
        c.addPath(path)
        c.strokePath()
    }

    private func drawRailingPosts(path: CGPath, color: UIColor, in c: CGContext) {
        c.setStrokeColor(color.withAlphaComponent(0.7).cgColor)
        c.setLineWidth(2)

        // Sample points along path every ~40pt
        let pathLength = approximatePathLength(path)
        let spacing: CGFloat = 40
        let count = max(1, Int(pathLength / spacing))
        for i in 0...count {
            let t = CGFloat(i) / CGFloat(count)
            if let pt = pointOnPath(path, at: t) {
                let angle = tangentOnPath(path, at: t)
                let dx = -sin(angle) * 14
                let dy = cos(angle) * 14
                c.move(to: CGPoint(x: pt.x - dx, y: pt.y - dy))
                c.addLine(to: CGPoint(x: pt.x + dx, y: pt.y + dy))
            }
        }
        c.strokePath()
    }

    // MARK: - Structures

    private func drawStructures(in c: CGContext) {
        let r = shape.color.r
        let g = shape.color.g
        let b = shape.color.b
        let darkBase = UIColor(red: r * 0.3, green: g * 0.3, blue: b * 0.3, alpha: 1)
        let darkTop = UIColor(red: r * 0.2, green: g * 0.2, blue: b * 0.2, alpha: 1)

        drawLadder(in: c, darkTop: darkTop, darkBase: darkBase)
        drawTopPlatform(in: c, darkTop: darkTop, darkBase: darkBase)
        drawPillar(in: c, darkTop: darkTop, darkBase: darkBase)
        drawLandingPlatform(in: c, darkTop: darkTop, darkBase: darkBase)
    }

    private func drawLadder(in c: CGContext, darkTop: UIColor, darkBase: UIColor) {
        let lx = layout.origin.x
        let ly = layout.groundY
        let lw = layout.ladderWidth
        let lh = layout.topY - layout.groundY - 10
        let pillarW: CGFloat = 8
        let r: CGFloat = 4

        // Left pole
        drawRoundedGradientRect(CGRect(x: lx, y: ly + 5, width: pillarW, height: lh), r: r,
                                top: darkTop, bottom: darkBase, in: c)
        // Right pole
        drawRoundedGradientRect(CGRect(x: lx + lw - pillarW, y: ly + 5, width: pillarW, height: lh), r: r,
                                top: darkTop, bottom: darkBase, in: c)
        // Rungs
        let rungCount = 6
        let rungSpacing = lh / CGFloat(rungCount)
        for i in 0..<rungCount {
            let y = ly + 5 + CGFloat(i) * rungSpacing
            drawRoundedGradientRect(CGRect(x: lx, y: y, width: lw, height: 5), r: 2,
                                    top: darkTop, bottom: darkTop, in: c)
        }
    }

    private func drawTopPlatform(in c: CGContext, darkTop: UIColor, darkBase: UIColor) {
        let rect = CGRect(x: layout.origin.x,
                          y: layout.topY - layout.platformThickness,
                          width: layout.slideStartX - layout.origin.x + 10,
                          height: layout.platformThickness)
        drawRoundedGradientRect(rect, r: 6, top: darkTop, bottom: darkBase, in: c)

        // Shadow below
        let shadowRect = rect.offsetBy(dx: 3, dy: -3)
        c.setFillColor(UIColor.black.withAlphaComponent(0.15).cgColor)
        c.fill(CGRect(origin: shadowRect.origin, size: shadowRect.size).insetBy(dx: 0, dy: -2))
    }

    private func drawPillar(in c: CGContext, darkTop: UIColor, darkBase: UIColor) {
        let midX = (layout.slideStartX + layout.slideEndX) / 2
        let midY = (layout.topY + layout.slideEndY) / 2
        let rect = CGRect(x: midX - 5, y: layout.groundY, width: 10, height: midY - layout.groundY)
        drawRoundedGradientRect(rect, r: 5, top: darkTop.withAlphaComponent(0.6), bottom: darkBase.withAlphaComponent(0.5), in: c)
    }

    private func drawLandingPlatform(in c: CGContext, darkTop: UIColor, darkBase: UIColor) {
        let rect = CGRect(x: layout.slideEndX + 15,
                          y: layout.groundY,
                          width: 70,
                          height: layout.bottomPlatformHeight)
        drawRoundedGradientRect(rect, r: 8, top: darkTop, bottom: darkBase, in: c)
    }

    // MARK: - Primitive helpers

    private func drawRoundedGradientRect(_ rect: CGRect, r: CGFloat,
                                         top: UIColor, bottom: UIColor,
                                         in c: CGContext) {
        c.saveGState()
        let path = UIBezierPath(roundedRect: rect, cornerRadius: r).cgPath
        c.addPath(path)
        c.clip()

        let colors = [top.cgColor, bottom.cgColor] as CFArray
        guard let gradient = CGGradient(colorsSpace: CGColorSpace(name: CGColorSpace.sRGB)!,
                                        colors: colors, locations: [0, 1]) else {
            c.restoreGState()
            return
        }
        c.drawLinearGradient(gradient,
                             start: CGPoint(x: rect.midX, y: rect.minY),
                             end: CGPoint(x: rect.midX, y: rect.maxY),
                             options: [])
        c.restoreGState()
    }

    // MARK: - Path math helpers

    private func approximatePathLength(_ path: CGPath) -> CGFloat {
        var length: CGFloat = 0
        var prev: CGPoint?
        path.applyWithBlock { elementPtr in
            let element = elementPtr.pointee
            switch element.type {
            case .moveToPoint, .addLineToPoint:
                let pt = element.points[0]
                if let p = prev { length += hypot(pt.x - p.x, pt.y - p.y) }
                prev = pt
            case .addQuadCurveToPoint:
                let cp = element.points[0]
                let ep = element.points[1]
                if let sp = prev {
                    // Rough approximation: sample along curve
                    for i in 1...8 {
                        let t = CGFloat(i) / 8
                        let x = (1-t)*(1-t)*sp.x + 2*(1-t)*t*cp.x + t*t*ep.x
                        let y = (1-t)*(1-t)*sp.y + 2*(1-t)*t*cp.y + t*t*ep.y
                        if let p = prev { length += hypot(x - p.x, y - p.y) }
                        prev = CGPoint(x: x, y: y)
                    }
                }
                prev = ep
            case .addCurveToPoint:
                let cp1 = element.points[0]
                let cp2 = element.points[1]
                let ep = element.points[2]
                if let sp = prev {
                    for i in 1...8 {
                        let t = CGFloat(i) / 8
                        let u = 1 - t
                        let x = u*u*u*sp.x + 3*u*u*t*cp1.x + 3*u*t*t*cp2.x + t*t*t*ep.x
                        let y = u*u*u*sp.y + 3*u*u*t*cp1.y + 3*u*t*t*cp2.y + t*t*t*ep.y
                        if let p = prev { length += hypot(x - p.x, y - p.y) }
                        prev = CGPoint(x: x, y: y)
                    }
                }
                prev = ep
            default: break
            }
        }
        return length
    }

    private func pointOnPath(_ path: CGPath, at t: CGFloat) -> CGPoint? {
        let length = approximatePathLength(path)
        guard length > 0 else { return nil }
        var target = t * length
        var prev: CGPoint?
        var result: CGPoint?
        var traveled: CGFloat = 0

        path.applyWithBlock { elementPtr in
            guard result == nil else { return }
            let element = elementPtr.pointee
            switch element.type {
            case .moveToPoint:
                prev = element.points[0]
            case .addLineToPoint:
                let ep = element.points[0]
                if let sp = prev {
                    let seg = hypot(ep.x - sp.x, ep.y - sp.y)
                    if traveled + seg >= target {
                        let f = seg > 0 ? (target - traveled) / seg : 0
                        result = CGPoint(x: sp.x + (ep.x - sp.x) * f, y: sp.y + (ep.y - sp.y) * f)
                    }
                    traveled += seg
                }
                prev = ep
            default: break
            }
        }
        return result ?? prev
    }

    private func tangentOnPath(_ path: CGPath, at t: CGFloat) -> CGFloat {
        let t0 = max(0, t - 0.001)
        let t1 = min(1, t + 0.001)
        guard let p0 = pointOnPath(path, at: t0),
              let p1 = pointOnPath(path, at: t1),
              hypot(p1.x - p0.x, p1.y - p0.y) > 0.0001 else { return 0 }
        return atan2(p1.y - p0.y, p1.x - p0.x)
    }

    // MARK: - Animation

    func fadeOut(duration: TimeInterval = 0.3) -> SKAction {
        SKAction.fadeOut(withDuration: duration)
    }

    func fadeIn(duration: TimeInterval = 0.3) -> SKAction {
        SKAction.fadeIn(withDuration: duration)
    }
}
