{"content": "import SpriteKit

final class CharacterNode: SKNode {
    let data: CharacterData
    private let sprite: SKSpriteNode
    private let shadowNode: SKSpriteNode

    /// 排队栏原位
    var homePosition: CGPoint = .zero

    /// 用于检测点击的圆形区域
    var tapRadius: CGFloat = 45

    init(data: CharacterData) {
        self.data = data

        // 角色纹理占位（后续 updateTexture 替换）
        let size = CGSize(width: 60, height: 80)
        let renderer = UIGraphicsImageRenderer(size: size)
        let image = renderer.image { ctx in
            let rect = CGRect(origin: .zero, size: size)
            ctx.cgContext.setFillColor(UIColor(
                red: data.color.r, green: data.color.g, blue: data.color.b, alpha: 1
            ).cgColor)
            ctx.cgContext.fillEllipse(in: rect)
        }

        sprite = SKSpriteNode(texture: SKTexture(image: image))
        sprite.setScale(data.scale)
        sprite.zPosition = 10

        // 地面阴影
        shadowNode = SKSpriteNode(color: SKColor.black.withAlphaComponent(0.25), size: CGSize(width: 50, height: 14))
        shadowNode.zPosition = 5

        super.init()
        addChild(shadowNode)
        addChild(sprite)
        shadowNode.position = CGPoint(x: 0, y: -size.height * data.scale / 2 + 7)
    }

    required init?(coder aDecoder: NSCoder) {
        fatalError("init(coder:) has not been implemented")
    }

    /// 更新纹理（下载完图片后调用）
    func updateTexture(_ texture: SKTexture) {
        sprite.texture = texture
        let texSize = texture.size()
        let scale = 80 / texSize.height
        sprite.size = CGSize(width: texSize.width * scale, height: 80)
    }

    // MARK: - 动作序列（弹簧物理化）

    /// 排队栏弹跳 — 弹簧感：放大 → 压缩 → 回弹超调 → 归位
    func bounceAction() -> SKAction {
        let scale = data.scale
        let grow = SKAction.scale(to: scale * 1.22, duration: 0.10)
        grow.timingMode = .easeOut
        let squish = SKAction.scale(to: scale * 0.88, duration: 0.12)
        squish.timingMode = .easeIn
        let overshoot = SKAction.scale(to: scale * 1.06, duration: 0.08)
        overshoot.timingMode = .easeOut
        let settle = SKAction.scale(to: scale, duration: 0.06)
        settle.timingMode = .easeIn

        // 同时轻微上移
        let up = SKAction.moveBy(x: 0, y: 12, duration: 0.10)
        up.timingMode = .easeOut
        let down = SKAction.moveBy(x: 0, y: -12, duration: 0.14)
        down.timingMode = .easeIn

        return SKAction.group([
            SKAction.sequence([grow, squish, overshoot, settle]),
            SKAction.sequence([up, down]),
        ])
    }

    /// 瞬移到滑梯顶部平台
    func teleportAction(to position: CGPoint) -> SKAction {
        let shrink = SKAction.scale(to: 0.08, duration: 0.12)
        shrink.timingMode = .easeIn
        let move = SKAction.move(to: position, duration: 0)
        let grow = SKAction.scale(to: data.scale * 1.08, duration: 0.10)
        grow.timingMode = .easeOut
        let settle = SKAction.scale(to: data.scale, duration: 0.08)
        settle.timingMode = .easeIn
        return SKAction.sequence([shrink, move, grow, settle])
    }

    /// 沿滑道滑下（带 squash & stretch 逐帧形变）
    func slideAction(path: CGPath, duration: TimeInterval) -> SKAction {
        let slide = SKAction.follow(path, asOffset: false, orientToPath: true, duration: duration)
        slide.timingMode = .easeInEaseOut

        // 逐帧形变：速度方向拉伸，垂直方向压缩
        let squash = SKAction.customAction(withDuration: duration) { [weak self] node, elapsed in
            guard let self else { return }
            let progress = elapsed / CGFloat(duration)
            // 加速→减速段形变更大
            let intensity: CGFloat
            if progress < 0.2 {
                intensity = progress / 0.2 * 0.15  // 加速段递增
            } else if progress > 0.8 {
                intensity = (1 - progress) / 0.2 * 0.15  // 减速段递减
            } else {
                intensity = 0.15  // 匀速段恒定
            }
            let stretchX = 1 + intensity
            let squishY = 1 - intensity * 0.7
            self.sprite.xScale = stretchX
            self.sprite.yScale = squishY
        }

        // 结束时恢复
        let reset = SKAction.run { [weak self] in
            self?.sprite.xScale = 1.0
            self?.sprite.yScale = 1.0
        }

        return SKAction.group([slide, squash, SKAction.sequence([
            SKAction.wait(forDuration: duration),
            reset,
        ])])
    }

    /// 着陆弹起 — 完整 squash & stretch 循环
    func landBounceAction() -> SKAction {
        let scale = data.scale
        // 撞击瞬间：横向展宽、纵向压扁
        let impact = SKAction.group([
            SKAction.scaleX(to: scale * 1.30, y: scale * 0.70, duration: 0.06),
            SKAction.moveBy(x: 0, y: -6, duration: 0.06),
        ])
        // 反弹拉伸
        let stretch = SKAction.group([
            SKAction.scaleX(to: scale * 0.82, y: scale * 1.20, duration: 0.08),
            SKAction.moveBy(x: 0, y: 22, duration: 0.08),
        ])
        // 回落归位
        let land = SKAction.group([
            SKAction.scale(to: scale, duration: 0.10),
            SKAction.moveBy(x: 0, y: -16, duration: 0.10),
        ])
        return SKAction.sequence([impact, stretch, land])
    }

    /// 走回排队栏（振幅随距离衰减）
    func returnAction(from: CGPoint, to: CGPoint) -> SKAction {
        let dx = to.x - from.x
        let dy = to.y - from.y
        let dist = hypot(dx, dy)
        let duration = max(0.5, dist / 200)

        let move = SKAction.move(to: to, duration: duration)
        move.timingMode = .easeInEaseOut

        let hops = Int(dist / 30)
        guard hops > 0 else { return move }

        // 跳跃振幅从大到小
        var actions: [SKAction] = []
        for i in 0..<hops {
            let fraction = CGFloat(i) / CGFloat(hops)
            let amplitude: CGFloat = 8 + 6 * (1 - fraction) // 14→8 pt
            let hop = SKAction.moveBy(x: 0, y: amplitude, duration: 0.07)
            hop.timingMode = .easeOut
            let drop = SKAction.moveBy(x: 0, y: -amplitude, duration: 0.07)
            drop.timingMode = .easeIn
            actions.append(hop)
            actions.append(drop)
        }
        let hopSequence = SKAction.sequence(actions)
        return SKAction.group([move, hopSequence])
    }

    /// 检查某个点是否命中此角色
    func hitTest(_ point: CGPoint) -> Bool {
        let dx = point.x - position.x
        let dy = point.y - position.y
        return hypot(dx, dy) < tapRadius
    }
}
