import UIKit

final class GameScene: SKScene {

    // MARK: - State

    private enum GameState {
        case idle
        case animating
    }

    private var state: GameState = .idle

    // MARK: - Slides

    private let slideShapes: [SlideShape] = [.straight, .curved, .wavy, .spiral]
    private var currentSlideIndex = 0
    private var currentSlideNode: SlideNode?
    private var slideLabel: SKLabelNode!

    // MARK: - Characters

    private var characterNodes: [CharacterNode] = []
    private let characterBarYFraction: CGFloat = 0.12

    // MARK: - Touch tracking (swipe vs tap)

    private var touchStart: CGPoint?

    // MARK: - Layout

    private func sceneLayout() -> SlideLayout {
        let sceneW = size.width
        let sceneH = size.height
        let barHeight = sceneH * 0.15
        let margin: CGFloat = 60

        return SlideLayout(
            origin: CGPoint(x: margin, y: barHeight + 20),
            totalWidth: sceneW - margin * 2 - 100,
            totalHeight: sceneH - barHeight - 80
        )
    }

    // MARK: - Scene init

    static func makeScene(size: CGSize) -> GameScene {
        let scene = GameScene(size: size)
        scene.scaleMode = .resizeFill
        return scene
    }

    override func didMove(to view: SKView) {
        backgroundColor = SKColor(red: 0.92, green: 0.96, blue: 0.88, alpha: 1)

        SoundManager.shared.preloadAll()

        setupBackground()
        setupSlideLabel()
        showSlide(at: currentSlideIndex, animated: false)
        setupCharacters()
    }

    // MARK: - Background

    private func setupBackground() {
        let bg = BackgroundNode(frame: CGRect(origin: .zero, size: size))
        addChild(bg)
    }

    // MARK: - Slide label

    private func setupSlideLabel() {
        slideLabel = SKLabelNode(fontNamed: "AvenirNext-Bold")
        slideLabel.fontSize = 32
        slideLabel.fontColor = SKColor.darkGray
        slideLabel.verticalAlignmentMode = .top
        slideLabel.horizontalAlignmentMode = .center
        slideLabel.position = CGPoint(x: size.width / 2, y: size.height - 20)
        slideLabel.zPosition = 100
        addChild(slideLabel)
    }

    private func updateLabel() {
        let shape = slideShapes[currentSlideIndex]
        let emoji: String
        switch shape {
        case .straight: emoji = "🔴"
        case .curved:   emoji = "🔵"
        case .wavy:     emoji = "🟢"
        case .spiral:   emoji = "🟣"
        }
        slideLabel.text = "\(shape.name) \(emoji)"

        // 标签微小弹跳
        slideLabel.removeAction(forKey: "labelBounce")
        let bounce = SKAction.sequence([
            SKAction.scale(to: 1.12, duration: 0.08),
            SKAction.scale(to: 0.95, duration: 0.08),
            SKAction.scale(to: 1.0, duration: 0.06),
        ])
        slideLabel.run(bounce, withKey: "labelBounce")
    }

    // MARK: - Slide management

    private func showSlide(at index: Int, animated: Bool) {
        let layout = sceneLayout()
        let shape = slideShapes[index]
        let newSlide = SlideNode(shape: shape, layout: layout)

        if animated, let old = currentSlideNode {
            // Transition particles
            let (r, g, b) = shape.color
            let color = SKColor(red: r, green: g, blue: b, alpha: 1)
            if let emitter = EffectsNode.transitionEmitter(color: color) as SKEmitterNode? {
                EffectsNode.burst(emitter, at: CGPoint(x: size.width / 2, y: size.height / 2), on: self)
            }

            let fadeOut = SKAction.sequence([
                SKAction.fadeOut(withDuration: 0.25),
                SKAction.removeFromParent(),
            ])
            old.run(fadeOut)
            newSlide.alpha = 0
            newSlide.run(SKAction.fadeIn(withDuration: 0.25))
        } else {
            currentSlideNode?.removeFromParent()
        }

        addChild(newSlide)
        currentSlideNode = newSlide
        currentSlideIndex = index
        updateLabel()
    }

    private func switchToSlide(_ index: Int) {
        guard index != currentSlideIndex, state == .idle else { return }
        state = .animating
        showSlide(at: index, animated: true)

        run(SKAction.sequence([
            SKAction.wait(forDuration: 0.35),
            SKAction.run { [weak self] in self?.state = .idle },
        ]))
    }

    // MARK: - Characters setup

    private func setupCharacters() {
        let sceneW = size.width
        let sceneH = size.height
        let barY = sceneH * characterBarYFraction
        let count = CharacterData.all.count
        let spacing = min(110, (sceneW - 120) / CGFloat(max(count, 1)))
        let totalWidth = spacing * CGFloat(count - 1)
        let startX = (sceneW - totalWidth) / 2

        for (i, data) in CharacterData.all.enumerated() {
            let node = CharacterNode(data: data)

            if let textureImage = UIImage(named: data.imageName) {
                node.updateTexture(SKTexture(image: textureImage))
            }

            let pos = CGPoint(x: startX + CGFloat(i) * spacing, y: barY)
            node.position = pos
            node.homePosition = pos
            addChild(node)
            characterNodes.append(node)
        }
    }

    // MARK: - Touch handling

    override func touchesBegan(_ touches: Set<UITouch>, with event: UIEvent?) {
        guard let touch = touches.first else { return }
        touchStart = touch.location(in: self)
    }

    override func touchesEnded(_ touches: Set<UITouch>, with event: UIEvent?) {
        guard let touch = touches.first, let start = touchStart else { return }
        let end = touch.location(in: self)
        let dx = end.x - start.x
        let dy = end.y - start.y
        let dist = hypot(dx, dy)

        if dist < 30 {
            handleTap(at: end)
            return
        }

        if abs(dx) > abs(dy) && abs(dx) > 40 {
            if dx > 0 {
                switchToSlide((currentSlideIndex - 1 + slideShapes.count) % slideShapes.count)
            } else {
                switchToSlide((currentSlideIndex + 1) % slideShapes.count)
            }
        }
    }

    private func handleTap(at point: CGPoint) {
        guard state == .idle else { return }

        for node in characterNodes {
            if node.hitTest(point) {
                startSlideSequence(for: node)
                return
            }
        }
    }

    // MARK: - Slide sequence

    private func startSlideSequence(for character: CharacterNode) {
        guard let slide = currentSlideNode else { return }
        state = .animating

        SoundManager.shared.play(.tap)

        let layout = sceneLayout()
        let topPos = CGPoint(x: layout.slideStartX, y: layout.topY + 15)
        let landingPos = CGPoint(x: layout.slideEndX + 40, y: layout.slideEndY)
        let returnPos = character.homePosition
        let path = slide.slidePath

        let duration: TimeInterval
        switch slideShapes[currentSlideIndex] {
        case .straight: duration = 1.0
        case .curved:   duration = 1.3
        case .wavy:     duration = 1.8
        case .spiral:   duration = 2.2
        }

        let (r, g, b) = slideShapes[currentSlideIndex].color
        let slideColor = SKColor(red: r, green: g, blue: b, alpha: 1)

        let sequence = SKAction.sequence([
            // Puff + bounce + teleport
            SKAction.run { [weak self] in
                guard let self else { return }
                EffectsNode.burst(EffectsNode.puffEmitter(), at: character.position, on: self)
            },
            character.bounceAction(),
            character.teleportAction(to: topPos),

            // Slide sound + spark particles
            SKAction.run { [weak self] in
                SoundManager.shared.play(.slide)
                guard let self else { return }
                let spark = EffectsNode.sparkEmitter(color: slideColor)
                spark.particlePosition = CGPoint(x: 0, y: -20)
                character.addChild(spark)
            },
            character.slideAction(path: path, duration: duration),

            // Stop slide, remove spark, play boing + star burst
            SKAction.run { [weak self] in
                SoundManager.shared.stop(.slide)
                SoundManager.shared.play(.boing)
                guard let self else { return }
                // Remove spark emitter from character
                character.children
                    .compactMap { $0 as? SKEmitterNode }
                    .forEach { $0.removeFromParent() }
                EffectsNode.burst(EffectsNode.starBurstEmitter(), at: character.position, on: self)
            },

            // Land bounce
            character.landBounceAction(),

            // Footsteps
            SKAction.run { SoundManager.shared.play(.footsteps) },
            character.returnAction(from: landingPos, to: returnPos),

            // Done
            SKAction.run { [weak self] in
                self?.state = .idle
            },
        ])

        character.run(sequence)
    }
}
